import sys

def solve():
    input_data = sys.stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx+=1
    for _ in range(t):
        n = int(input_data[idx]); idx+=1
        a = list(map(int, input_data[idx:idx+n])); idx+=n

        prefix = [0]*(n+1)
        for i in range(n):
            prefix[i+1] = prefix[i] + a[i]

        def range_sum(l, r):
            return prefix[r] - prefix[l]

        def check(k):
            if k*(k+1)//2 > n:
                return False
            if k == 0:
                return True

            INF = float('inf')

            # Initialize for segment k (length 1, the last segment)
            length = 1
            dp = [-INF]*n  # -INF means invalid position
            for j in range(n - length + 1):
                dp[j] = range_sum(j, j+length)

            # suffix max of valid dp values
            suf_max = [-INF]*(n+1)
            for j in range(n-1, -1, -1):
                suf_max[j] = max(suf_max[j+1], dp[j])

            # Process segments k-1, k-2, ..., 1
            for seg in range(k-1, 0, -1):
                length = k + 1 - seg
                new_dp = [-INF]*n
                for j in range(n - length + 1):
                    s = range_sum(j, j+length)
                    nxt_start = j + length
                    if nxt_start <= n and suf_max[nxt_start] > s:
                        new_dp[j] = s

                dp = new_dp
                suf_max = [-INF]*(n+1)
                for j in range(n-1, -1, -1):
                    suf_max[j] = max(suf_max[j+1], dp[j])

            # Check if any valid starting position for segment 1 (length k)
            return any(v > -INF for v in dp)

        hi = 0
        while (hi+1)*(hi+2)//2 <= n:
            hi += 1

        ans = 0
        lo, hi = 0, hi
        while lo <= hi:
            mid = (lo+hi)//2
            if check(mid):
                ans = mid
                lo = mid+1
            else:
                hi = mid-1

        print(ans)

